// src/main/kotlin/com/helios/auth/controller/HealthController.kt

@RestController
class HealthController(
    private val dataSource: DataSource,
    private val redisTemplate: RedisTemplate<String, String>
) {
    @GetMapping("/health")
    fun health(): ResponseEntity<Map<String, Any>> {
        val checks = mutableMapOf<String, String>()
        var healthy = true

        try {
            dataSource.connection.use { it.isValid(2) }
            checks["postgres"] = "up"
        } catch (e: Exception) {
            checks["postgres"] = "down"
            healthy = false
        }

        try {
            redisTemplate.connectionFactory?.connection?.ping()
            checks["redis"] = "up"
        } catch (e: Exception) {
            checks["redis"] = "down"
            healthy = false
        }

        val status = if (healthy) HttpStatus.OK else HttpStatus.SERVICE_UNAVAILABLE
        return ResponseEntity.status(status).body(mapOf("status" to if (healthy) "healthy" else "unhealthy", "checks" to checks))
    }

    // Lightweight liveness probe — no dependency checks
    @GetMapping("/health/live")
    fun liveness() = mapOf("status" to "alive")
}
```

Key points:
- `/health` — readiness probe, checks Postgres + Redis. Returns 503 if either is down.
- `/health/live` — liveness probe, always 200 if the process is up.
- Configure ALB target group to hit `/health` for readiness, `/health/live` for liveness in the EKS pod spec.

If auth-service uses gRPC exclusively (no REST controller), you'll need to either expose this on a separate HTTP port (common pattern) or use the [gRPC Health Checking Protocol](https://github.com/grpc/grpc/blob/master/doc/health-checking.md). Most ALBs expect HTTP, so a separate HTTP port (e.g., 8081) for health is the usual approach.

